import {{ Injectable }} from '@nestjs/common';
import {{ TaxService }} from './models/tax.model';
import {{ TaxServiceRepository }} from './repositories/tax.repository';

@Injectable()
export class TaxServiceService {{
  constructor(
    private readonly repository: TaxServiceRepository,
  ) {{}}

  async findAll(): Promise<TaxService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<TaxService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<TaxService>): Promise<TaxService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<TaxService>): Promise<TaxService> {{
    return this.repository.update(id, data);
  }}
}}
